  for (let i = 0; i < 8; i++) { const xx = (i + 0.5) / 8 * w; x.beginPath(); for (let yy = 0; yy <= h; yy += 3) { const wob = Math.sin(yy * 0.4 + i * 1.3) * 2.2; yy === 0 ? x.moveTo(xx + wob, yy) : x.lineTo(xx + wob, yy) } x.stroke() }
