  const sand = [0.87, 0.79, 0.57], poleC = [0.64, 0.68, 0.72], red = [0.78, 0.42, 0.36], wood = [0.6, 0.45, 0.3], plat = [0.5, 0.62, 0.72], P = []
  P.push({ g: box, m: M(4, 0.2, 4, 5, 0.4, 5), c: sand }) // 砂場
