    if (!(o.isMesh || o.isInstancedMesh) || !o.geometry) continue
    if (o.userData && (o.userData.noChunk || o.userData.yatoGround)) continue // 地面は対象外＝足元は常に近傍が見えるので分割しても距離カリングがほぼ効かず、draw callだけ嵩む（地面はフラットで頂点も安い）。単一メッシュのまま
