  const win = new THREE.Mesh(new THREE.BoxGeometry(1.5, 0.46, 2.0), vehGlass); win.position.set(0, 1.2, -0.1); g.add(win)
  for (const [wx, wz] of [[0.86, 1.3], [-0.86, 1.3], [0.86, -1.3], [-0.86, -1.3]]) { const t = new THREE.Mesh(new THREE.CylinderGeometry(0.32, 0.32, 0.26, 12), vehTyre); t.rotation.z = Math.PI / 2; t.position.set(wx, 0.32, wz); g.add(t); wheels.push(t) }
