  for (const [wx, wz] of [[0.74, 1.0], [-0.74, 1.0], [0.74, -1.0], [-0.74, -1.0]]) { const t = new THREE.Mesh(new THREE.CylinderGeometry(0.28, 0.28, 0.22, 12), vehTyre); t.rotation.z = Math.PI / 2; t.position.set(wx, 0.28, wz); g.add(t); wheels.push(t) }
