  x.fillStyle = '#3a6a4a'; x.fillRect(0, 0, 100, 22); x.fillStyle = '#fdf6e6'; x.font = 'bold 13px sans-serif'; x.textAlign = 'center'; x.fillText('時こく表', 50, 16)
  x.textAlign = 'left'
  const rows = [['6', '20  50'], ['7', '10  35'], ['8', '05  40'], ['9', '15'], ['10', '00  45'], ['…', ''], ['17', '10  50'], ['18', '20'], ['19', '05  40']]
  for (let i = 0; i < rows.length; i++) { const y = 34 + i * 12; x.fillStyle = '#9a3a2a'; x.font = 'bold 10px sans-serif'; x.fillText(rows[i][0], 7, y); x.fillStyle = '#4a4a44'; x.font = '9px sans-serif'; x.fillText(rows[i][1], 30, y); x.strokeStyle = '#ddd5c0'; x.lineWidth = 1; x.beginPath(); x.moveTo(5, y + 3); x.lineTo(95, y + 3); x.stroke() }
