// ── 夕方のカラス（夕焼け空を ねぐらへ帰っていく＝「そろそろ帰る時間」）──
const crows = []
function makeCrow() {
  const g = new THREE.Group()
  const mat = new THREE.MeshBasicMaterial({ color: 0x23252f, fog: false, side: THREE.DoubleSide, transparent: true, opacity: 0 })
  const body = new THREE.Mesh(new THREE.SphereGeometry(0.18, 8, 6), mat); body.scale.set(1, 0.7, 2.4); g.add(body)
  // 翼は体の中心をピボットにして はばたかせる（翼端が上下する＝鳥のV字）
  const wl = new THREE.Group(); g.add(wl)
  const wlm = new THREE.Mesh(new THREE.PlaneGeometry(1.3, 0.42), mat); wlm.position.x = -0.7; wlm.rotation.x = -Math.PI / 2; wl.add(wlm)
  const wr = new THREE.Group(); g.add(wr)
  const wrm = new THREE.Mesh(new THREE.PlaneGeometry(1.3, 0.42), mat); wrm.position.x = 0.7; wrm.rotation.x = -Math.PI / 2; wr.add(wrm)
  g.rotation.y = -Math.PI / 2 // 進行方向（+x）を向く
  g.userData = { wl, wr, mat, off: Math.random() * 240, sp: 5 + Math.random() * 2, alt: 17 + Math.random() * 9, lane: -85 + Math.random() * 45, flap: 7 + Math.random() * 3, fph: Math.random() * 6.28 }
  g.visible = false; scene.add(g); crows.push(g)
}
for (let i = 0; i < 5; i++) makeCrow()

// ── ツバメ（昼〜夕に低く速く弧を描いて舞う＝夏の空の生気。プレイヤーの周りを8の字に飛び、夜は塒へ）──
const swallows = []
function makeSwallow() {
  const g = new THREE.Group()
  const back = new THREE.MeshBasicMaterial({ color: 0x2a3340, fog: false, side: THREE.DoubleSide, transparent: true, opacity: 0 }) // 紺黒の背
  const belly = new THREE.MeshBasicMaterial({ color: 0xf2eee4, fog: false, side: THREE.DoubleSide, transparent: true, opacity: 0 }) // 白い腹
  const body = new THREE.Mesh(new THREE.SphereGeometry(0.12, 8, 6), back); body.scale.set(1, 0.7, 2.6); g.add(body)
  const bel = new THREE.Mesh(new THREE.SphereGeometry(0.1, 8, 6), belly); bel.scale.set(1, 0.55, 2.0); bel.position.y = -0.04; g.add(bel)
  const wl = new THREE.Group(); g.add(wl); const wlm = new THREE.Mesh(new THREE.PlaneGeometry(0.95, 0.26), back); wlm.position.x = -0.5; wlm.rotation.x = -Math.PI / 2; wl.add(wlm)
  const wr = new THREE.Group(); g.add(wr); const wrm = new THREE.Mesh(new THREE.PlaneGeometry(0.95, 0.26), back); wrm.position.x = 0.5; wrm.rotation.x = -Math.PI / 2; wr.add(wrm)
  const tail = new THREE.Mesh(new THREE.ConeGeometry(0.12, 0.5, 4), back); tail.rotation.x = -Math.PI / 2; tail.position.z = -0.4; tail.scale.set(0.5, 1, 1); g.add(tail) // 燕尾
  g.userData = { wl, wr, back, belly, off: Math.random() * 6.28, sp: 0.42 + Math.random() * 0.22, R: 24 + Math.random() * 22, R2: 13 + Math.random() * 12, alt: 10 + Math.random() * 8, flap: 15 + Math.random() * 6, fph: Math.random() * 6.28, px: 0, pz: 0, hd: 0 }
  g.visible = false; scene.add(g); swallows.push(g)
}
for (let i = 0; i < 5; i++) makeSwallow()

// ── 遠くの人影（道沿いをゆっくり歩く＝“誰かが暮らしている”気配。近づかず遠くに・夜は家へ帰る。道は開けているので建物にめり込まない）2026-06-24 ──
const farFolk = []
// 遠くの人影＝以前は円柱＋球の“のっぺり棒人間”で、近づくと「人がよくわからない」状態だった（ユーザー指摘2026-06-27）。
// 主人公と同じ頭身のチビ（大きな頭・顔・手足・麦わら帽子/髪）に作り直す。フェード用に専用の半透明マテリアル(M)を集める。
function makeFolk() {
  const g = new THREE.Group(), mats = []
  const M = (c) => { const m = new THREE.MeshToonMaterial({ color: c, gradientMap: GRAD, transparent: true, opacity: 0 }); mats.push(m); return m }
  const adult = Math.random() < 0.45
  const skin = [0xf0c49c, 0xe8b890, 0xeab584, 0xf2cba0][(Math.random() * 4) | 0]
  const shirt = [0xe8e2d0, 0x9fb8d0, 0xd6b0a0, 0xcfd2c2, 0xe2c79a, 0xb9c4cc, 0xc8d0b0, 0xd8a4a0, 0x8fb89c][(Math.random() * 9) | 0]
  const pant = [0x3a4a6a, 0x5a4a3a, 0x46688a, 0x6a5a4a, 0x8a6a4a, 0x4a5a52][(Math.random() * 6) | 0]
  const hairCol = [0x4a3a28, 0x52402c, 0x5a4a36][(Math.random() * 3) | 0] // 遠景の人影の髪も黒に潰さない濃茶へ（2026-06-29）
  const skinM = M(skin), shirtM = M(shirt), pantM = M(pant), shoeM = M(0x4a4038)
  // 脚（股関節ピボットで歩行スイング）
  const legL = new THREE.Group(), legR = new THREE.Group()
  for (const [grp, sx] of [[legL, -0.07], [legR, 0.07]]) { grp.position.set(sx, 0.62, 0); g.add(grp)
    const thigh = new THREE.Mesh(new THREE.CapsuleGeometry(0.05, 0.46, 4, 6), pantM); thigh.position.y = -0.27; grp.add(thigh)
    const foot = new THREE.Mesh(new THREE.SphereGeometry(0.062, 6, 5), shoeM); foot.scale.set(1, 0.66, 1.5); foot.position.set(0, -0.52, 0.03); grp.add(foot) }
  // 胴（少しすぼまる）
  const body = new THREE.Mesh(new THREE.CylinderGeometry(0.14, 0.12, 0.5, 8), shirtM); body.position.y = 0.95; g.add(body)
  // 腕（肩ピボットでスイング）
  const armL = new THREE.Group(), armR = new THREE.Group()
  for (const [grp, sx] of [[armL, -0.155], [armR, 0.155]]) { grp.position.set(sx, 1.14, 0); g.add(grp)
    const upper = new THREE.Mesh(new THREE.CapsuleGeometry(0.043, 0.4, 4, 6), shirtM); upper.position.y = -0.2; grp.add(upper)
    const hand = new THREE.Mesh(new THREE.SphereGeometry(0.05, 6, 5), skinM); hand.position.y = -0.42; grp.add(hand) }
  // 首・頭（チビ＝大きめの頭）
  const neck = new THREE.Mesh(new THREE.CylinderGeometry(0.05, 0.055, 0.08, 6), skinM); neck.position.y = 1.25; g.add(neck)
  const head = new THREE.Mesh(new THREE.SphereGeometry(0.155, 12, 10), skinM); head.scale.set(1.05, 1.12, 1.03); head.position.y = 1.41; g.add(head)
  for (const sx of [-0.058, 0.058]) { // 目＝白目＋瞳（点目をやめ主人公/村人と同じ作りに近づける＝質感を統一・ユーザー指摘2026-06-28）。M()でフェードに乗る
    const sc = new THREE.Mesh(new THREE.SphereGeometry(0.028, 8, 7), M(0xf6f4ee)); sc.scale.set(0.9, 1.15, 0.42); sc.position.set(sx, 1.422, 0.116); g.add(sc) // 白目
    const ir = new THREE.Mesh(new THREE.SphereGeometry(0.017, 8, 7), M(0x352a20)); ir.scale.set(0.98, 1.04, 0.5); ir.position.set(sx, 1.418, 0.132); g.add(ir) } // 瞳
  if (Math.random() < 0.5) { // 麦わら帽子（夏）
    const brim = new THREE.Mesh(new THREE.CylinderGeometry(0.235, 0.255, 0.028, 14), M(0xd8b46e)); brim.position.y = 1.53; g.add(brim)
    const cap = new THREE.Mesh(new THREE.SphereGeometry(0.145, 10, 8, 0, 6.28, 0, 1.25), M(0xe2c178)); cap.position.y = 1.55; g.add(cap)
  } else { const hair = new THREE.Mesh(new THREE.SphereGeometry(0.166, 10, 8, 0, 6.28, 0, 1.95), M(hairCol)); hair.position.y = 1.44; g.add(hair) }
  g.scale.setScalar(adult ? 1.05 : 0.82) // 大人/子どもで背丈差
  g.traverse((o) => { if (o.isMesh) o.castShadow = false }) // 動くので影マップへ焼かない（残像防止）
  g.userData = { tx: 0, tz: 0, sp: 0.9 + Math.random() * 0.5, ph: Math.random() * 6.28, has: false, mats, legL, legR, armL, armR, wph: 0 }
  g.visible = false; scene.add(g); farFolk.push(g)
}
for (let i = 0; i < 6; i++) makeFolk() // 遠くの人影を4→6に（街に暮らす気配を増やす・ユーザー要望2026-06-27）
// 道の点を空間ハッシュ化＝人影が「プレイヤー近くの道」を素早く選べる（全道からランダムだと2km四方で近くに当たらない）
const ROADPT_CELL = 40, roadGrid = new Map()
for (const rd of SG.roads) { const p = rd.p; for (let k = 0; k < p.length - 1; k++) { const a = p[k], b = p[k + 1], dx = b[0] - a[0], dz = b[1] - a[1], l = Math.hypot(dx, dz) || 1; for (let t = 0; t < l; t += 9) { const x = a[0] + dx * t / l, z = a[1] + dz * t / l; if (heightAtYato(x, z) < 2) continue; const key = Math.floor(x / ROADPT_CELL) + ',' + Math.floor(z / ROADPT_CELL); let arr = roadGrid.get(key); if (!arr) { arr = []; roadGrid.set(key, arr) } arr.push([x, z]) } } }

// ── 足元の砂ぼこり（走ると ふっと土が舞う）──
const DUSTN = 36
const dustPos = new Float32Array(DUSTN * 3).fill(-9999)
const dustVel = new Float32Array(DUSTN * 3)
const dustLife = new Float32Array(DUSTN)
const dustGeo = new THREE.BufferGeometry()
dustGeo.setAttribute('position', new THREE.BufferAttribute(dustPos, 3))
const dustPts = new THREE.Points(dustGeo, new THREE.PointsMaterial({ color: 0xd8c6a2, size: 0.42, transparent: true, opacity: 0.45, depthWrite: false, fog: true }))
dustPts.frustumCulled = false; dustPts.layers.set(1); scene.add(dustPts) // 空気中のちりもインク線の法線パスから除外
let dustHead = 0
function spawnDust(x, y, z) {
  const i = dustHead; dustHead = (dustHead + 1) % DUSTN
  dustPos[i * 3] = x + (Math.random() - 0.5) * 0.3; dustPos[i * 3 + 1] = y; dustPos[i * 3 + 2] = z + (Math.random() - 0.5) * 0.3
  dustVel[i * 3] = (Math.random() - 0.5) * 0.5; dustVel[i * 3 + 1] = 0.4 + Math.random() * 0.4; dustVel[i * 3 + 2] = (Math.random() - 0.5) * 0.5
  dustLife[i] = 0.55
}
let lastStepS = 0

// ── 虫採り（つかまえる遊び）：蝶・カブトムシ・セミ ──
const caught = { count: 0, kinds: {}, first: {} } // first[種]＝はじめて出会った{day,tw,place}＝ずかんを“数”でなく“思い出”に（P2・後方互換で追加）
const catchables = []
for (const b of butterflies) catchables.push({ obj: b, kind: 'チョウ', done: false })
// 蝉の胴と翅を「全個体で共有する1個ずつの合成ジオメトリ」に焼き込む（蝶BFLY_WING_GEO/とんぼDRF_WING_GEOと同じ思想＝個体ごとにジオメトリ/draw callを増やさない）
const CICADA_BODY_GEO = (() => { // 頭/胸/腹の節＋複眼を頂点色つきで1メッシュに合成（draw call=1）
  const parts = []
  const tint = (geo, hex) => { const c = new THREE.Color(hex), n = geo.attributes.position.count, arr = new Float32Array(n * 3); for (let i = 0; i < n; i++) { arr[i * 3] = c.r; arr[i * 3 + 1] = c.g; arr[i * 3 + 2] = c.b } geo.setAttribute('color', new THREE.BufferAttribute(arr, 3)); return geo }
  // 配色：木の幹で“暗いブロブ”に潰れないよう一段明るい茶緑へ（アブラゼミの褐色＝幹に止まっても胴の節が読める・2026-06-29）
  const ab = new THREE.ConeGeometry(0.13, 0.34, 8); ab.rotateX(Math.PI / 2); ab.translate(0, 0, -0.1); parts.push(tint(ab, 0x6f6a52)) // 腹（後ろへ細る節）
  const th = new THREE.SphereGeometry(0.13, 9, 7); th.scale(1, 0.85, 1.1); th.translate(0, 0.01, 0.06); parts.push(tint(th, 0x837c61)) // 胸（一番ふくらむ・少し明るく）
  const hd = new THREE.SphereGeometry(0.085, 8, 6); hd.scale(1.25, 0.8, 0.7); hd.translate(0, 0, 0.18); parts.push(tint(hd, 0x6f6a52)) // 頭（横に広い）
  for (const s of [-1, 1]) { const ey = new THREE.SphereGeometry(0.028, 6, 5); ey.translate(s * 0.07, 0.01, 0.2); parts.push(tint(ey, 0x3a352a)) } // 複眼（左右）
  return mergeGeometries(parts, false)
})()
const CICADA_BODY_MAT = new THREE.MeshToonMaterial({ vertexColors: true, gradientMap: GRAD }) // 頂点色で頭/胸/腹/眼を塗り分け（材質は共有）
const CICADA_WING_GEO = (() => { // 背に伏せた半透明V字の翅2枚を1メッシュに合成（draw call=1）
  const parts = []
  for (const s of [-1, 1]) { const w = new THREE.PlaneGeometry(0.16, 0.34); w.translate(0, -0.10, 0); w.rotateX(-Math.PI / 2 + 0.32); w.rotateZ(s * 0.34); w.translate(s * 0.04, 0.06, 0); parts.push(w) }
  return mergeGeometries(parts, false)
})()
const CICADA_WING_MAT = new THREE.MeshBasicMaterial({ color: 0xe7eef2, transparent: true, opacity: 0.5, side: THREE.DoubleSide, depthWrite: false }) // 蝉の翅＝透明で翅脈が透ける質感（とんぼの翅に倣う）。形が読めるよう不透明度を上げた(0.34→0.5)＋やや白く＝幹の前で翅のV字が分かる（2026-06-29）
function makeBug(x, y, z, kind) {
  const g = new THREE.Group()
  if (kind === 'カブトムシ') {
    // 配色：木の幹で“黒いシミ”に潰れず角のシルエットが立つよう、本体は一段明るい飴色の茶＋背に淡いハイライト、角は本体よりさらに明るい飴茶で輪郭を浮かせる（2026-06-29）
    const body = new THREE.Mesh(new THREE.SphereGeometry(0.28, 10, 8), toon(0x5a4226)); body.scale.set(1, 0.7, 1.35); g.add(body) // 本体＝明るめの飴色の茶
    const shine = new THREE.Mesh(new THREE.SphereGeometry(0.2, 10, 7), toon(0x7a5c34)); shine.scale.set(0.86, 0.5, 1.1); shine.position.set(0, 0.11, 0.02); g.add(shine) // 背の照り（明度差のハイライト＝甲虫の艶）
    const horn = new THREE.Mesh(new THREE.ConeGeometry(0.05, 0.32, 6), toon(0x73552f)); horn.position.set(0, 0.13, 0.34); horn.rotation.x = -0.7; g.add(horn) // 頭角（長く前へ反る・本体より明るい飴茶でシルエットを立てる）
    const thHorn = new THREE.Mesh(new THREE.ConeGeometry(0.038, 0.16, 6), toon(0x73552f)); thHorn.position.set(0, 0.15, 0.12); thHorn.rotation.x = -0.35; g.add(thHorn) // 胸角（短くヘラ状＝頭角と対になる2本目）
  } else if (kind === 'クワガタ') {
    const body = new THREE.Mesh(new THREE.SphereGeometry(0.28, 10, 8), toon(0x3a2a18)); body.scale.set(1, 0.5, 1.45); g.add(body) // 平たい黒褐色の甲
    const shine = new THREE.Mesh(new THREE.SphereGeometry(0.2, 10, 7), toon(0x5a4228)); shine.scale.set(0.8, 0.4, 1.1); shine.position.set(0, 0.08, 0); g.add(shine) // 背の照り
    const head = new THREE.Mesh(new THREE.SphereGeometry(0.12, 8, 6), toon(0x2c2013)); head.scale.set(1, 0.7, 0.9); head.position.set(0, 0.05, 0.32); g.add(head)
    for (const s of [-1, 1]) { const mand = new THREE.Mesh(new THREE.BoxGeometry(0.032, 0.032, 0.26), toon(0x241a0f)); mand.position.set(s * 0.08, 0.06, 0.46); mand.rotation.y = s * 0.42; g.add(mand); const tip = new THREE.Mesh(new THREE.BoxGeometry(0.032, 0.032, 0.11), toon(0x241a0f)); tip.position.set(s * 0.03, 0.06, 0.6); tip.rotation.y = s * 1.15; g.add(tip) } // 大あご（前へ＋先が内へ＝クワガタ）
  } else if (kind === 'バッタ') {
    const body = new THREE.Mesh(new THREE.SphereGeometry(0.12, 8, 6), toon(0x6f9040)); body.scale.set(0.85, 0.85, 2.3); g.add(body) // 緑の細長い胴
    const head = new THREE.Mesh(new THREE.SphereGeometry(0.085, 8, 6), toon(0x7c9a48)); head.position.set(0, 0.02, 0.26); g.add(head)
    for (const s of [-1, 1]) { const thigh = new THREE.Mesh(new THREE.CylinderGeometry(0.045, 0.02, 0.22, 6), toon(0x5c7c34)); thigh.position.set(s * 0.1, 0.03, -0.08); thigh.rotation.set(0.7, 0, s * 0.4); g.add(thigh); const shin = new THREE.Mesh(new THREE.CylinderGeometry(0.012, 0.012, 0.2, 5), toon(0x4c6a2c)); shin.position.set(s * 0.14, 0.06, -0.2); shin.rotation.set(-0.5, 0, s * 0.2); g.add(shin) } // 大きな後脚（跳ぶ足）
    for (const s of [-1, 1]) { const ant = new THREE.Mesh(new THREE.CylinderGeometry(0.006, 0.006, 0.22, 4), toon(0x4a5a2c)); ant.position.set(s * 0.03, 0.1, 0.36); ant.rotation.x = -0.7; g.add(ant) } // 触角
  } else {
    // セミ＝頭/胸/腹の節ある胴（合成）＋背に伏せた半透明のV字の翅2枚（合成）。“黒い球”からの脱却。各1draw call
    const body = new THREE.Mesh(CICADA_BODY_GEO, CICADA_BODY_MAT); g.add(body)
    const wings = new THREE.Mesh(CICADA_WING_GEO, CICADA_WING_MAT); wings.layers.set(1); g.add(wings) // layer1＝インク法線パスから除外（透明翅が黒い四角にならない）
  }
  g.traverse((o) => { if (o.isMesh) o.castShadow = true })
  g.position.set(x, y, z); scene.add(g)
  catchables.push({ obj: g, kind, done: false })
}
