    const upper = thinLimb(limbCap(P.armR, P.upperArm, skin)); upper.position.y = -P.upperArm / 2 - 0.04; sh.add(upper) // まっすぐ細い二の腕
    const elbow = new THREE.Group(); elbow.position.y = -P.upperArm; sh.add(elbow)
    const elbowCap = noLine(new THREE.Mesh(new THREE.SphereGeometry(P.armR * 0.96, 8, 6), skin)); elbow.add(elbowCap)
    const fore = thinLimb(limbCap(P.armR * 0.9, P.fore, skin)); fore.position.y = -P.fore / 2; elbow.add(fore) // まっすぐ細い前腕
    const hand = noLine(new THREE.Mesh(new THREE.SphereGeometry(0.048, 12, 10), skin)); hand.scale.set(0.92, 1.06, 0.7); hand.position.y = -P.fore - 0.005; elbow.add(hand)
    g.add(sh)
