  const bagTip = new THREE.Mesh(new THREE.SphereGeometry(0.05, 10, 7, 0, Math.PI * 2, 0, Math.PI * 0.55), netMat); bagTip.rotation.x = Math.PI - 0.7; bagTip.position.set(0, -0.446, -0.40); bagPivot.add(bagTip) // 袋の底（しなった先端の丸み・体と反対側）
