// ── 子どもたちのキャッチボール（夏休みの昼間・小学校の広場で遊ぶ子どもの群れ）C12・2026-06-26 ──
const kidsCatch = (() => {
  const ctr = [3072, -150] // 小学校の広場の東がわ（平らな空き地・池や飛び石を避けた開けたところ）
  const mk = (px, pz, fx, fz, sh, sk, hr) => { const g = makeVillager(px, pz, { shirt: sh, skirt: 0x3a4a6a, skin: sk, hair: hr, boy: true, simple: false, adult: false, hat: false, hairStyle: 'short', garment: 'shorts', build: 0.9 + Math.random() * 0.12, headW: 0.96 + Math.random() * 0.08, eyeSc: 0.95 + Math.random() * 0.2, scale: 0.82 + Math.random() * 0.08, shoe: 0xcfcabd, face: 0, info: { name: '', byPhase: { noon: [''] } } })
    g.position.set(px, heightAt(px, pz), pz); g.rotation.y = Math.atan2(fx - px, fz - pz); return g } // fx,fz の方を向く
  const A = [ctr[0] + 0.5, ctr[1] - 3], B = [ctr[0] - 0.5, ctr[1] + 3] // 約6m離れて向かい合う投げ手2人（南北に投げ合う＝東の道から弧が横に見える）
  const a = mk(A[0], A[1], B[0], B[1], 0xe07a4a, 0xf0c49c, 0x2a2218) // 半袖の子
  const b = mk(B[0], B[1], A[0], A[1], 0x4f86b0, 0xeab584, 0x35291c) // 青シャツの子
  const w = mk(ctr[0] - 4.2, ctr[1] - 0.4, ctr[0], ctr[1], 0xe8d24a, 0xe8b890, 0x46371f) // 見ている子（試合の方を向く）
  const ball = new THREE.Mesh(new THREE.SphereGeometry(0.072, 10, 8), toon(0xeae0c0)); ball.castShadow = true; addOutline(ball, 0.012); scene.add(ball) // 白っぽいゴムボール
  return { a, b, w, ball, A: [A[0], heightAt(A[0], A[1]), A[1]], B: [B[0], heightAt(B[0], B[1]), B[1]], t: Math.random(), from: 0 }
})()

// ── NPC配置の安全検証（水域/建物に立たせない＝ユーザー指摘2026-06-27「それ池の中だよ」）──
//   配置前に必ず「水域でない・障害物(建物)でない・開けた地面か」を判定し、ダメなら近くの安全な地面へ逃がす。
const npcInWater = (x, z) => !!(SG && SG.waters && SG.waters.some((w) => w.p && w.p.length >= 3 && pip(x, z, w.p)))
function npcInCollider(x, z) { // ★性能：全コライダー(約1.2万)走査をやめ衝突グリッドの近傍3x3だけ見る（点を含むコライダーは必ずその点のセルに登録済＝等価で高速・2026-06-28）
  const ci = Math.floor(x / CG_CELL), cj = Math.floor(z / CG_CELL)
  for (let di = -1; di <= 1; di++) for (let dj = -1; dj <= 1; dj++) { const a = cgrid.get(cgKey(ci + di, cj + dj)); if (!a) continue
    for (const idx of a) { const c = colliders[idx]; if (c.box) { const dx = x - c.x, dz = z - c.z, lx = c.c * dx - c.s * dz, lz = c.s * dx + c.c * dz; if (Math.abs(lx) < c.hw && Math.abs(lz) < c.hd) return true } else if ((x - c.x) ** 2 + (z - c.z) ** 2 < c.r * c.r) return true } }
  return false }
function npcSpotOk(x, z, clearR) { clearR = clearR || 0
  const ng = (px, pz) => npcInWater(px, pz) || npcInCollider(px, pz) || onYatoRoadCore(px, pz) // 水/建物/道路の舗装のどれかなら不可
  if (ng(x, z)) return false // 中心が水/建物/道のど真ん中はNG
  for (const rad of [clearR * 0.55, clearR]) { if (rad < 0.3) continue; for (let a = 0; a < 6.2832; a += 0.78) { if (ng(x + Math.cos(a) * rad, z + Math.sin(a) * rad)) return false } } // 二人の足元〜輪の縁まで全周が地面（道/水/建物に出ない）
  return true
}
function placeNPCOnLand(x, z, clearR, maxR) { maxR = maxR || 40
  if (npcSpotOk(x, z, clearR)) return { x, z }
  for (let rr = 3; rr <= maxR; rr += 3) for (let a = 0; a < 6.2832; a += 0.42) { const ex = x + Math.cos(a) * rr, ez = z + Math.sin(a) * rr; if (npcSpotOk(ex, ez, clearR)) return { x: ex, z: ez } } // 近くから螺旋状に開けた地面を探す
  return null
}
// 「建物に“深く”埋まっているか」＝壁際(コライダーのパディング内＝自然)は許し、足元のパッド0.6mより内側に入っている物だけを不具合とみなす
function deepInBuilding(x, z) { for (const c of colliders) { if (c.box) { const dx = x - c.x, dz = z - c.z, lx = c.c * dx - c.s * dz, lz = c.s * dx + c.c * dz; if (Math.abs(lx) < c.hw - 0.6 && Math.abs(lz) < c.hd - 0.6) return true } else if ((x - c.x) ** 2 + (z - c.z) ** 2 < (c.r - 0.6) ** 2) return true } return false }
// ── 獅子ヶ谷（yato）の「話せる住人」＝商店街のおばさん／花屋のおばさん／軒先の年配の人。──
//   旧プロト町の townLady と同じ仕組み（makeVillager の info.byPhase ＋ npcs 配列 ＋ startDialogue のフラグ）を再利用。
//   これで yato 常駐のプレイヤーでも絵日記の metShop / gotOmake が立つ（街まで歩いた wentTown は yato の商店街到達でも立てる）。
//   配置は placeNPCOnLand で必ず「水/建物/道を避けた開けた地面」へスナップ＝接地（heightAtYato）も確実。道(客)の方を向く。
const yatoFolk = [] // yato の立ち話す住人（毎フレーム：息づかい＋近づくと気づいてこちらを向く）
function makeYatoResident(ax, az, faceX, faceZ, opt) {
  const spot = placeNPCOnLand(ax, az, 0.7, 14) || { x: ax, z: az } // 開けた地面へスナップ（見つからなければ素点）
  const p = makeVillager(spot.x, spot.z, opt)
  p.rotation.y = Math.atan2(faceX - spot.x, faceZ - spot.z) // 道(客)＝最寄りの道の方を向く
  yatoFolk.push(p); return p
}
