const PENLIGHT_COLS = [0xff5aa0, 0x6affc0, 0x5ab0ff, 0xffd23a, 0xff8a3a, 0xb06aff] // ペンライトの蛍光色（桃/緑/青/黄/橙/紫）
function addRunGroup(cx, cz, r, opt) {
  opt = opt || {}
  const p = placeNPCOnLand(cx, cz, r + 1.2, 55); if (!p) { console.warn('runGroup配置不可(水/建物)', cx, cz); return } // 輪ごと開けた地面に乗る所へ
  cx = p.x; cz = p.z
  const pk = (a) => PENLIGHT_COLS[Math.floor(Math.random() * PENLIGHT_COLS.length)]
  const pa = opt.penlight ? pk() : null, pb = opt.penlight ? pk() : null // 夜のペンライト＝二人で別々の色
  runGroups.push({ a: makePlayKid(cx, cz, 0xe07a4a, 0xf0c49c, 0x5a4632, pa), b: makePlayKid(cx, cz, 0x4f86b0, 0xeab584, 0x6e4d34, pb), cx, cz, r, ph: Math.random() * 6, night: !!opt.night, venue: opt.venue || null }) // 髪の近黒廃止（2026-07-04）
}
function updateRunKids(dt) {
  for (const G of runGroups) {
    // 夜のペンライト組＝お祭りの会場が出ている晩（その会場グループが見えている＝開催日の夕〜夜）だけ。それ以外の組は昼に駆け回る
    const active = G.night ? (onYato && tday > 0.6 && tday < 0.99 && (!G.venue || G.venue.g.visible)) : (onYato && tday > 0.12 && tday < 0.6)
    const vis = active && Math.hypot(boy.position.x - G.cx, boy.position.z - G.cz) < 140
    if (G.a.visible !== vis) { G.a.visible = vis; G.b.visible = vis }
    if (!vis) continue
    G.ph += dt * 0.8
    const lay = (g, ang, wb) => { const x = G.cx + Math.cos(ang) * G.r, z = G.cz + Math.sin(ang) * G.r * 0.66 // 楕円の周回（トラックを駆ける）
      g.position.set(x, heightAtYato(x, z), z)
      g.rotation.y = Math.atan2(-Math.sin(ang), Math.cos(ang) * 0.66) // 進行方向（接線）を向く
      const wph = G.ph * 9 + wb; g.position.y += Math.abs(Math.sin(wph)) * 0.09 // 大きく弾む＝走り
      const sw = Math.sin(wph) * 0.9, u = g.userData; u.walking = true // walking=走り＝VRMの脚ブリッジで脚を動かす（立ち止まらず常に走る・前傾はグループのrotation.xをVRMが継承）
      u.legL.rotation.x = sw; u.legR.rotation.x = -sw; u.armL.rotation.x = -sw * 1.1; u.armR.rotation.x = sw * 1.1
      g.rotation.x = 0.16 } // 前傾
    lay(G.a, G.ph, 0); lay(G.b, G.ph - 0.55, 1.4) // bはaを追いかける
  }
}
