function showDlgLine(text) {
  if (dlgType && dlgType.timer) { clearInterval(dlgType.timer); dlgType.timer = null }
  if (dlgMoreEl) dlgMoreEl.style.opacity = '0' // 表示中は「▼」を隠す
  if (reduceMotion) { dlgTextEl.textContent = text; dlgType = { full: text, n: text.length, timer: null }; if (dlgMoreEl) dlgMoreEl.style.opacity = '1'; return } // 酔い対策ONなら一気に表示
  const voice = dlgVoice(dlgWho) // 話者の性別(garment)×年齢(adult)で声色（文字送り音）を変える＝女の子は高く/男の大人は今のまま/子供は全く別
  dlgType = { full: text, n: 0, timer: null }
  dlgTextEl.textContent = ''
  dlgType.timer = setInterval(() => {
    dlgType.n = Math.min(dlgType.full.length, dlgType.n + 1)
    dlgTextEl.textContent = dlgType.full.slice(0, dlgType.n)
    const ch = dlgType.full[dlgType.n - 1] // 1文字ごとにやわらかい音＝台詞が“生き物の声”に（空白・約物は鳴らさない）
    if (ch && !/[\s、。「」（）！？…ー　]/.test(ch) && Math.random() < 0.55) playDlgBlip(voice.p, voice.w, voice.d)
    if (dlgType.n >= dlgType.full.length) { clearInterval(dlgType.timer); dlgType.timer = null; if (dlgMoreEl) dlgMoreEl.style.opacity = '1' } // 出切ったら「▼ つづきはタップ」を出す
  }, 40) // 1文字あたり約40ms＝ゆっくり読める速さ
}
const phaseOf = (t) => (t < 0.18 ? 'morning' : t < 0.5 ? 'noon' : t < 0.78 ? 'evening' : 'night')
function startDialogue() {
  const who = talkTarget || villager
  const info = who.userData.info
  // その日の関係の台詞（あれば順序を保って見せる）→ なければ時間帯のプールから1つ選ぶ
  // P2：同じ人に話すたび寸分同じ台詞が即リピート＝“また会いたい”の最大の敵。プールから1本選び直前と同じは避ける（連投ガード）
  const arc = info.arcByDay && info.arcByDay[arcStage()] // H1：関係は段階(初対面/打ちとけ/別れ)で進む＝ひと夏(7日)に対応
  let lines
  if (arc) { lines = arc }
  else {
    const pool = info.byPhase[phaseOf(tday)] || info.byPhase.noon
    let pick = pool[Math.floor(Math.random() * pool.length)]
    if (pool.length > 1) { let guard = 0; while (pick === who.userData._lastLine && guard++ < 6) pick = pool[Math.floor(Math.random() * pool.length)] } // 直前と同じ一言は避ける
    who.userData._lastLine = pick
    // P2：通算日数で深まる世間話＋初対面vs再訪。その日はじめて話す時だけ、関係の段階(初対面/打ちとけ/別れ)に応じた一言を添えてから世間話へ＝“覚えていてくれる”温かさ
    const st = arcStage()
    if (info.arcGreet && info.arcGreet[st] && who.userData._greetedDay !== day) { who.userData._greetedDay = day; lines = [info.arcGreet[st], pick] }
    else lines = [pick]
  }
  dialogue = { lines, idx: 0 }
  dlgWho = who // カメラが二人を画に収める寄り（止め絵）に使う
  dlgNameEl.textContent = info.name
  showDlgLine(lines[0])
  dialogueEl.style.display = 'block'
  void dialogueEl.offsetHeight; dialogueEl.classList.add('show') // 吹き出しはふわっとフェードイン（レイアウト確定→.showでopacity/上がり）
  document.body.classList.add('talking') // 会話中は下の操作ボタン（ドック等）を隠す＝吹き出しと重ならず読みやすい（2026-06-29）
  npcEl.style.display = 'none'
  endPuni()
  if (who === villager) todayFlags.metGirl = true
  if (who === villager && day >= TOTAL_DAYS) { gotOmamori = true; try { localStorage.setItem('hn3d_omamori', '1') } catch (e) {} } // 最終日に会えたら おまもりを受け取る
  if (who === townLady) todayFlags.metShop = true
  if (who === townLady && tday > 0.6 && tday < 0.86 && !todayFlags.gotOmake) { todayFlags.gotOmake = true; showToast('おばさんが トマトを ひとつ おまけして くれた。') } // 夕方の「おまけ」を実際にもらえる
  // 獅子ヶ谷（yato）の商店街の住人＝旧プロト町の townLady と同じ絵日記フラグを再利用（yato 常駐でも metShop/gotOmake/wentTown が立つ）
  if (who === yatoShopLady || who === yatoFlowerLady) { todayFlags.metShop = true; todayFlags.wentTown = true } // 商店のおばさんと話した＝商店街まで歩いた証
  if (who === yatoShopLady && tday > 0.6 && tday < 0.86 && !todayFlags.gotOmake) { todayFlags.gotOmake = true; showToast('おばさんが トマトを ひとつ おまけして くれた。') } // 八百屋のおばさんも夕方は「おまけ」をくれる
  if (who === grandma && tday > 0.3 && tday < 0.62 && !todayFlags.lamune) { todayFlags.lamune = true; showToast('おばあちゃんが ラムネを くれた。よく ひえていた。') } // H3：昼間に縁側のおばあちゃんが冷えたラムネをくれる（絵日記のlamuneに連動）
  who.rotation.y = Math.atan2(boy.position.x - who.position.x, boy.position.z - who.position.z) // こちらを向く
}

// ── 「ひと夏（数日）」＋絵日記（その日やったこと→翌日への予告／夏の終わり）。H1：3日→7日へ拡張 ──
const TOTAL_DAYS = 7 // ひと夏の日数。最終日に「夏の終わり」。お囃子/花火はfestDay()で3日周期にローテ＝どの日もどこかでお祭り
const festDay = () => ((day - 1) % 3) + 1 // 祭り会場の開催日(1..3)＝ひと夏のあいだ会場をめぐってお祭りが続く
const arcStage = () => day === 1 ? 1 : day >= TOTAL_DAYS ? 3 : 2 // 女の子との関係：初対面(1)→打ちとけ(2..)→夏の終わりの別れ(最終日)
let day = 1
let gotOmamori = false // 夏の終わりに女の子から おまもりを もらった（日をまたいで残る＝関係の証）
try { gotOmamori = localStorage.getItem('hn3d_omamori') === '1' } catch (e) {}
