function taisoStamp(i) {
  const c = document.createElement('canvas'); c.width = c.height = 52; const x = c.getContext('2d')
  const R = '#c0392b'; x.strokeStyle = R; x.fillStyle = R; x.lineCap = 'round'
  x.save(); x.translate(26, 26); x.rotate((((i * 37) % 13) / 13 - 0.5) * 0.5)
  x.lineWidth = 2.4; x.beginPath(); x.arc(0, 0, 21, 0, 7); x.stroke(); x.lineWidth = 2
  const M = i % 7
  if (M === 0) { for (let p = 0; p < 5; p++) { const a = p / 5 * 6.283 - 1.57; x.beginPath(); x.arc(Math.cos(a) * 7, Math.sin(a) * 7, 5, 0, 7); x.stroke() } x.beginPath(); x.arc(0, 0, 3, 0, 7); x.fill() } // アサガオ
  else if (M === 1) { x.beginPath(); x.ellipse(0, 3, 5, 9, 0, 0, 7); x.stroke(); for (const s of [-1, 1]) { x.beginPath(); x.ellipse(s * 7, 0, 7, 4, s * 0.5, 0, 7); x.stroke() } } // セミ
  else if (M === 2) { for (let p = 0; p < 8; p++) { const a = p / 8 * 6.283; x.beginPath(); x.ellipse(Math.cos(a) * 10, Math.sin(a) * 10, 4, 2.2, a, 0, 7); x.stroke() } x.beginPath(); x.arc(0, 0, 5, 0, 7); x.fill() } // ひまわり
  else if (M === 3) { x.beginPath(); x.ellipse(0, 4, 8, 10, 0, 0, 7); x.stroke(); x.beginPath(); x.moveTo(0, -4); x.lineTo(0, -15); x.lineTo(-4, -19); x.moveTo(0, -15); x.lineTo(4, -19); x.stroke() } // カブト
  else if (M === 4) { x.beginPath(); x.arc(0, -1, 13, 0.15, Math.PI - 0.15); x.stroke(); x.beginPath(); x.moveTo(-13, -1); x.lineTo(13, -1); x.stroke(); for (const dx of [-5, 0, 5]) { x.beginPath(); x.arc(dx, 5, 1.2, 0, 7); x.fill() } } // 西瓜
  else if (M === 5) { x.beginPath(); x.arc(0, -3, 8, Math.PI, 0); x.stroke(); x.beginPath(); x.moveTo(0, -3); x.lineTo(0, 9); x.stroke(); x.beginPath(); x.arc(0, 12, 3, 0, 7); x.stroke() } // 風鈴
  else { for (let p = 0; p < 8; p++) { const a = p / 8 * 6.283; x.beginPath(); x.moveTo(Math.cos(a) * 4, Math.sin(a) * 4); x.lineTo(Math.cos(a) * 15, Math.sin(a) * 15); x.stroke(); x.beginPath(); x.arc(Math.cos(a) * 16, Math.sin(a) * 16, 1.4, 0, 7); x.fill() } } // 花火
  x.restore()
  x.globalCompositeOperation = 'destination-out'; for (let k = 0; k < 16; k++) { x.globalAlpha = 0.1 + ((i * 7 + k * 11) % 10) / 10 * 0.22; x.beginPath(); x.arc((i * 13 + k * 17) % 52, (i * 29 + k * 23) % 52, 1 + (k % 3), 0, 7); x.fill() } // ゴム印のかすれ
  x.globalAlpha = 1; x.globalCompositeOperation = 'source-over'
  return c.toDataURL()
}
