function segDist2(px, pz, ax, az, bx, bz) { const dx = bx - ax, dz = bz - az, l2 = dx * dx + dz * dz; let t = l2 ? ((px - ax) * dx + (pz - az) * dz) / l2 : 0; t = t < 0 ? 0 : t > 1 ? 1 : t; return Math.hypot(px - (ax + t * dx), pz - (az + t * dz)) }
function nearestPondForFishing(x, z) {
  let best = null, bestD = 1e9
  for (const P of YATO_PONDS) {
    if (Math.hypot(x - P.cx, z - P.cz) > P.br + 12) continue // 粗いふるい（外接円＋余裕）
    if (pip(x, z, P.p)) return P // 水の上に立っていれば即これ
    const p = P.p; let ed = 1e9
    for (let i = 0, j = p.length - 1; i < p.length; j = i++) ed = Math.min(ed, segDist2(x, z, p[j][0], p[j][1], p[i][0], p[i][1]))
    if (ed < bestD) { bestD = ed; best = P }
  }
  return bestD <= 7 ? best : null // 岸から7m以内なら「釣れる」
}
