const fishRod = new THREE.Group()
{ const pole = new THREE.Mesh(new THREE.CylinderGeometry(0.011, 0.022, 1.7, 6), toon(0x7a5230)); pole.position.y = 0.85; fishRod.add(pole) // 竹竿
  const grip = new THREE.Mesh(new THREE.CylinderGeometry(0.026, 0.026, 0.18, 6), toon(0x4a3a26)); grip.position.y = 0.09; fishRod.add(grip) } // 握り
