  floatMesh.visible = true
  boy.rotation.y = Math.atan2(fx - boy.position.x, fz - boy.position.z) // 浮きの方を向いて構える
  fishCastT = 0.5 // 竿を振った余韻（竿先が前→上へ戻る）
  playPlop(); spawnRipple(fx, fz) // 浮きが水に落ちる「ぽちゃん」＋波紋
  fishState = 'wait'; showToast('…あたりを まつ')
