    // 花火大会の間は時間をゆっくり進める＝夏のクライマックスを長く味わう
    const fwSlow = FIREWORK.days.indexOf(festDay()) >= 0 && tday >= FIREWORK.from && tday <= FIREWORK.to
    const sitFlow = mode === 'sit' ? 5 : 1 // B1：座っている間は時間が速く流れる＝夕焼けが少しずつ色を変えていくのを眺められる（間を味わう）
