          u.head.rotation.x += (0.42 - u.head.rotation.x) * Math.min(1, dt * 4) // 手もと（地面）を見る
          u.armR.rotation.x += (-0.62 - u.armR.rotation.x) * Math.min(1, dt * 5)
          u.armR.rotation.z += ((0.22 + s * 0.32) - u.armR.rotation.z) * Math.min(1, dt * 6) // 左右に掃く
