    if (u.w) { const fl = Math.sin(tsec * 30 + u.ph) * 0.42; for (const wg of u.w) wg.m.rotation.x = wg.base + wg.s * fl } // 翅のはばたき（静止していた畑の赤とんぼに動きを・2026-07-05）
