    { const cdx = boy.position.x - c.cx, cdz = boy.position.z - c.cz; if (cdx * cdx + cdz * cdz > LOD_BUG2) { c.obj.visible = nf < 0.96; _perfAnim.bug.skip++; continue } } // 約90m以遠＝夜/エリアの可視だけ安く更新し、heightAt と羽ばたきは省く
