// ── VRMテクスチャ加工の共通ヘルパー（様式統一の要＝同じVRoid絵柄のまま役を作り分ける・2026-07-07） ──
// マテリアルのmapをcanvasに写し、描き終えたらapply()で差し戻す
function texCanvas(m) {
  const img = m.map.image
  const cv = document.createElement('canvas'); cv.width = img.width; cv.height = img.height
  const ctx = cv.getContext('2d'); ctx.drawImage(img, 0, 0)
  return { cv, ctx, apply() { const tex = new THREE.CanvasTexture(cv)
    tex.flipY = m.map.flipY; tex.colorSpace = m.map.colorSpace; tex.wrapS = m.map.wrapS; tex.wrapT = m.map.wrapT
    m.map = tex; if (m.shadeMultiplyTexture) m.shadeMultiplyTexture = tex; m.needsUpdate = true } }
}
// 紺（暗くて青寄り）の画素だけ別の布色に描き換える＝制服のベスト/スカートを白シャツや赤スカートへ。元の陰影は写す
function recolorNavy(vrm, nameRe, fr = 1, fg = 1, fb = 1) {
  vrm.scene.traverse((o) => { if (!o.isMesh || !o.material) return
    for (const m of (Array.isArray(o.material) ? o.material : [o.material])) {
      if (!m.name || !nameRe.test(m.name) || !m.map || !m.map.image) continue
      const t2 = texCanvas(m)
      const d = t2.ctx.getImageData(0, 0, t2.cv.width, t2.cv.height)
      for (let i = 0; i < d.data.length; i += 4) { const r = d.data[i], g = d.data[i + 1], b = d.data[i + 2]
        const lum = (r + g + b) / 3
        if (lum < 135 && b > r) { const t = Math.min(252, 205 + lum * 0.38)
          d.data[i] = Math.min(255, t * fr); d.data[i + 1] = Math.min(255, t * fg); d.data[i + 2] = Math.min(255, t * fb + 2) } }
      t2.ctx.putImageData(d, 0, 0); t2.apply() } })
}
// 暗い画素を白系へ持ち上げる（黒ソックス→白ソックス・黒ローファー→白ズック等）。元の陰影は薄く残す
function liftDark(vrm, nameRe, th, to) {
  vrm.scene.traverse((o) => { if (!o.isMesh || !o.material) return
    for (const m of (Array.isArray(o.material) ? o.material : [o.material])) {
      if (!m.name || !nameRe.test(m.name) || !m.map || !m.map.image) continue
      const t2 = texCanvas(m)
      const d = t2.ctx.getImageData(0, 0, t2.cv.width, t2.cv.height)
      for (let i = 0; i < d.data.length; i += 4) { const lum = (d.data[i] + d.data[i + 1] + d.data[i + 2]) / 3
        if (lum < th && d.data[i + 3] > 100) { const t = Math.min(250, to + lum * 0.25)
          d.data[i] = t; d.data[i + 1] = t - 2; d.data[i + 2] = t - 8 } }
      t2.ctx.putImageData(d, 0, 0); t2.apply() } })
}
// 顔テクスチャへ老いを直接描き込む＝ほうれい線・目尻/下まぶた/額のしわ・こけ頬。beardで白ひげ・tanで日焼けの膜
// 座標は篠/桜田の顔テクスチャ実物(1024角・正面顔が中央)を目視して設計。VRoidの標準レイアウト前提
function agedFace(vrm, opts = {}) {
  let fm = null, bm = null
  vrm.scene.traverse((o) => { if (!o.isMesh || !o.material) return
    for (const m of (Array.isArray(o.material) ? o.material : [o.material])) { if (!m.name) continue
      if (/Face/.test(m.name) && /SKIN/.test(m.name) && m.map && m.map.image) fm = fm || m
      if (/FaceBrow/.test(m.name)) bm = bm || m } })
  if (bm && bm.color) bm.color.set(0xbdb9af) // 眉を灰へ（乗算＝濃茶の眉が灰茶になる）
  if (!fm) return
  const { cv, ctx, apply } = texCanvas(fm)
  const s = cv.width / 1024; ctx.lineCap = 'round'
  const q = (x1, y1, cx1, cy1, x2, y2, w, a) => { ctx.strokeStyle = '#a1705d'; ctx.globalAlpha = a; ctx.lineWidth = w * s
    ctx.beginPath(); ctx.moveTo(x1 * s, y1 * s); ctx.quadraticCurveTo(cx1 * s, cy1 * s, x2 * s, y2 * s); ctx.stroke() }
  if (opts.wrinkles) {
    q(474, 700, 434, 740, 448, 788, 4, 0.42); q(542, 700, 582, 740, 568, 788, 4, 0.42) // ほうれい線（小鼻の脇→口の横へ）
    q(458, 784, 446, 806, 449, 826, 3, 0.30); q(558, 784, 570, 806, 567, 826, 3, 0.30) // 口元の下の線
    q(266, 556, 246, 558, 230, 552, 3, 0.38); q(268, 576, 248, 584, 233, 592, 3, 0.34) // 目尻（左）
    q(758, 556, 778, 558, 794, 552, 3, 0.38); q(756, 576, 776, 584, 791, 592, 3, 0.34) // 目尻（右）
    q(292, 632, 330, 650, 370, 637, 3, 0.26); q(654, 637, 694, 650, 732, 632, 3, 0.26) // 下まぶたのたるみ
    q(372, 330, 512, 313, 652, 330, 4, 0.26); q(384, 376, 512, 361, 640, 376, 4, 0.22) // 額の横じわ
    q(487, 438, 483, 459, 486, 478, 3, 0.26); q(537, 438, 541, 459, 538, 478, 3, 0.26) // 眉間
    ctx.globalAlpha = 0.07; ctx.fillStyle = '#8a6a58' // こけ頬のうす影
    ctx.beginPath(); ctx.ellipse(300 * s, 700 * s, 52 * s, 78 * s, 0.2, 0, Math.PI * 2); ctx.fill()
    ctx.beginPath(); ctx.ellipse(724 * s, 700 * s, 52 * s, 78 * s, -0.2, 0, Math.PI * 2); ctx.fill()
  }
  if (opts.mild) { // 中年（おばさん）＝ほうれい線を控えめに＋ごく薄い目尻だけ。老け過ぎない（額/眉間/こけ頬は描かず、おばあちゃんとは分ける）
    q(476, 704, 440, 742, 452, 786, 3, 0.24); q(540, 704, 576, 742, 564, 786, 3, 0.24) // ほうれい線（うすく）
    q(268, 560, 250, 562, 236, 556, 2.4, 0.18); q(756, 560, 774, 562, 788, 556, 2.4, 0.18) // 目尻（ごく薄く）
  }
  if (opts.beard) { // 白ひげ＝まずあご/鼻下に薄い白の下地→短い毛を多数（白灰2色）。細い線だけだと縮小表示で消える
    ctx.globalAlpha = 0.45; ctx.fillStyle = '#e2dccf'
    ctx.beginPath(); ctx.ellipse(512 * s, 838 * s, 128 * s, 58 * s, 0, 0, Math.PI * 2); ctx.fill() // あごの下地
    ctx.beginPath(); ctx.ellipse(512 * s, 750 * s, 78 * s, 15 * s, 0, 0, Math.PI * 2); ctx.fill() // 鼻下の下地
    const hair = (x, y, len) => { ctx.strokeStyle = Math.random() < 0.65 ? '#eee8dc' : '#a29a8e'
      ctx.globalAlpha = 0.95; ctx.lineWidth = 4 * s
      ctx.beginPath(); ctx.moveTo(x * s, y * s); ctx.lineTo((x + (Math.random() - 0.5) * 6) * s, (y + len) * s); ctx.stroke() }
    for (let i = 0; i < 300; i++) { const a = Math.PI * (0.18 + 0.64 * Math.random())
      const rx = 148 + Math.random() * 28, ry = 96 + Math.random() * 22
      const x = 512 + Math.cos(a) * rx, y = 772 + Math.sin(a) * ry
      if (y < 792) continue // 口の高さより下だけ（頬の上まで生やさない）
      hair(x, y, 8 + Math.random() * 9) }
    for (let i = 0; i < 110; i++) hair(444 + Math.random() * 136, 734 + Math.random() * 18, 10) // 口ひげ
  }
  if (opts.tan) { ctx.globalAlpha = 1; ctx.globalCompositeOperation = 'multiply'
    ctx.fillStyle = opts.tan; ctx.fillRect(0, 0, cv.width, cv.height); ctx.globalCompositeOperation = 'source-over' } // 日焼けの膜（乗算）
  if (opts.freckles) { ctx.globalAlpha = 0.4; ctx.fillStyle = '#b97748'
    for (const [fx, fy] of [[318, 688], [342, 700], [300, 706], [706, 688], [682, 700], [724, 706], [496, 700], [528, 700]]) {
      ctx.beginPath(); ctx.arc(fx * s, fy * s, 3.2 * s, 0, Math.PI * 2); ctx.fill() } } // そばかす（鼻の頭と両ほほ）
  ctx.globalAlpha = 1
  apply()
}
// 麦わら帽子（頭ボーンへ・共通）。withBand=false で無地（帯なし）
function strawHat(head, color = 0xe6c074, withBand = true) {
  const straw = hatToon(color)
  const brim = new THREE.Mesh(new THREE.CylinderGeometry(0.175, 0.182, 0.012, 18), straw)
  const crown = new THREE.Mesh(new THREE.CylinderGeometry(0.092, 0.108, 0.085, 14), straw)
  brim.position.set(0, 0.133, 0.012); crown.position.set(0, 0.172, 0.012)
  brim.rotation.x = 0.03; crown.rotation.x = 0.03
  head.add(brim, crown)
  if (withBand) { const band = new THREE.Mesh(new THREE.CylinderGeometry(0.109, 0.111, 0.026, 14), new THREE.MeshToonMaterial({ color: 0xb03a2e, gradientMap: GRAD_HAT, emissive: 0x30100c }))
    band.position.set(0, 0.140, 0.012); band.rotation.x = 0.03; head.add(band) }
  return { brim, crown }
}
// 野球帽（平成初期の定番）＝VRMの頭ボーンに付ける版（strawHatと同じ頭ローカル座標系＝この後headScaleで一緒に拡大される）。布の暗色はcharToon(影の床高め)で黒沈み回避
function ballCap(head, col = 0x33517e) {
  const m = charToon(col)
  // ★頭ボーンの向きを実測（_capdir.mjs）＝局所+zは後頭部・顔は-z（faceDotPz=-1）。方向のあるツバは必ず-z（顔前）へ。straw帽は円対称なので無問題だった
  const dome = new THREE.Mesh(new THREE.SphereGeometry(0.123, 18, 12, 0, Math.PI * 2, 0, Math.PI * 0.5), m); dome.scale.set(1.03, 0.9, 1.06); dome.position.set(0, 0.104, 0.004); head.add(dome) // 頭を覆う浅めのドーム（やや大きめ＝跳ね毛の根元を覆い、低めに座らせる）
  const peak = new THREE.Mesh(new THREE.BoxGeometry(0.188, 0.016, 0.135), m); peak.position.set(0, 0.108, -0.16); peak.rotation.x = 0.1; head.add(peak) // 前ツバ（顔前=-z）＝わずかに反らせる（目は隠さない）
  const btn = new THREE.Mesh(new THREE.SphereGeometry(0.013, 8, 8), m); btn.position.set(0, 0.205, 0.004); head.add(btn) // てっぺんのボタン
  return { dome, peak, btn }
}
