      if (/AccessoryNeck/.test(m.name)) m.visible = false // ネクタイを消す（夏の普段着へ）
      else if (/HairBack/.test(m.name)) m.visible = false // 腰までの後ろ髪を消して短髪に（男の普段の頭・boyize/grandmaizeと同手法）
