      x.fillStyle = '#241812'; x.beginPath(); x.arc(ex, ey + 3, 9.5, 0, Math.PI * 2); x.fill()
      x.fillStyle = 'rgba(255,255,255,0.95)'; x.beginPath(); x.arc(ex - 7, ey - 8, 6.5, 0, Math.PI * 2); x.fill()
