    // ★寸法は必ずrawボーン（見えているスキンの実骨格）で測る。正規化ボーンのworld座標は実寸と一致しない（実測2026-07-07：腰0.83=肩の高さになった）
    const wp = (n) => { const p = hu.getRawBoneNode(n).getWorldPosition(new THREE.Vector3()); return boy.worldToLocal(p) }
