      footL: nb(L + 'Foot'), footR: nb(R + 'Foot'),
      armL: nb(L + 'UpperArm'), armR: nb(R + 'UpperArm'),
      elbL: nb(L + 'LowerArm'), elbR: nb(R + 'LowerArm'),
      head: nb('head'), chest: nb('chest') || nb('spine'),
