//   よあけ0=4:30/あさ0.1=6:00/0.22=8:30/南中0.45=12:00/ゆうがた0.6=16:30/ゆうぐれ0.72=18:30/よる0.82=20:00/よふけ0.92=21:30/1.0=23:00
//   ※旧・線形(1日=17.5h)は tday0.6=14:37 となり「時計は昼すぎなのに世界は夕方でお祭りが始まる」ズレ（ユーザー指摘2026-07-02）
let setClockTimer = null
const CLOCK_ANCH = [[0, 4.5], [0.1, 6], [0.22, 8.5], [0.45, 12], [0.6, 16.5], [0.72, 18.5], [0.82, 20], [0.92, 21.5], [1, 23]]
function updateSetClock() {
  if (!settingsEl || !settingsEl.classList.contains('on')) { if (setClockTimer) { clearInterval(setClockTimer); setClockTimer = null } return } // どの経路で閉じても次のtickで止まる
  let hf = 23
  for (let i = 1; i < CLOCK_ANCH.length; i++) if (tday <= CLOCK_ANCH[i][0]) { const [t0, h0] = CLOCK_ANCH[i - 1], [t1, h1] = CLOCK_ANCH[i]; hf = h0 + (h1 - h0) * ((tday - t0) / (t1 - t0)); break }
  const H = Math.floor(((hf % 24) + 24) % 24), M = Math.floor((((hf % 1) + 1) % 1) * 60)
  const hAng = ((H % 12) + M / 60) * 30, mAng = M * 6
  const hEl = document.getElementById('clk-h'), mEl = document.getElementById('clk-m'), lab = document.getElementById('set-clock-label')
  if (hEl) hEl.setAttribute('transform', `rotate(${hAng.toFixed(1)} 50 50)`)
  if (mEl) mEl.setAttribute('transform', `rotate(${mAng.toFixed(1)} 50 50)`)
  if (lab) { const ap = H < 12 ? 'ごぜん' : 'ごご', h12 = (H % 12) === 0 ? 12 : (H % 12); lab.textContent = `${ap} ${h12}じ ${M.toString().padStart(2, '0')}ふん ・ ${timeWord(tday)}` }
}
