  YATO_PONDS, // 検証用：谷戸の釣り場一覧
  _yatoBugs() { return catchables.filter((c) => !c.done && c.obj.position.x > 2000).map((c) => ({ x: c.obj.position.x, y: c.obj.position.y, z: c.obj.position.z, kind: c.kind })) }, // 検証用：谷戸の虫の位置（虫採りが谷戸で成立するか）
  _npf(x, z) { const p = nearestPondForFishing(x, z); return p ? { cx: Math.round(p.cx), cz: Math.round(p.cz), br: Math.round(p.br) } : null }, // 検証用：その点で釣れる池（update非依存で直接判定）
  villager, townLady, townKid, farmer, cat, pedestrians, // 検証用
